    elif g=='D_S07':
        if age<45:
            base={'A':0.020,'B':0.035,'C':0.84}.get(p,0.08)+0.05*rec+0.020*scenario; sigma={'A':0.025,'B':0.04,'C':0.08}.get(p,0.06)
        elif age<75:
